-- Insert 45 new bodyweight strength exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Tempo Bodyweight Squat', 'tempo-bodyweight-squat', 'Tempo Bodyweight Squat is a tempo/eccentric bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'INTERMEDIATE', 8, 3, 8, 40, 90, 130, 'Slow-tempo squat that turns air-squat leverage into a real strength stimulus through time under tension, bracing, depth ownership, and repeatable knee/hip alignment. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Squat / Knee-Dominant Bodyweight Strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_tempo_bodyweight_squat_strength', '{"primary_joint_actions":["hip_flexion","knee_flexion","ankle_dorsiflexion","hip_extension","knee_extension"],"primary_tissues":["quadriceps","glutes","adductors","calves"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Tempo Bodyweight Squat is a tempo/eccentric bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Clear a non-slip training space and choose a variation the athlete can control without pain.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Start each repetition from a still, organized position.","Lower slowly through the prescribed range; do not drop, bounce, or rush the eccentric.","Drive through the concentric portion with strong intent while keeping the same body line and joint path.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."]}'::jsonb),
  ('Pause Bodyweight Squat', 'pause-bodyweight-squat', 'Pause Bodyweight Squat is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'INTERMEDIATE', 8, 3, 8, 40, 90, 130, 'Bottom-position pause removes bounce, builds positional strength, and teaches force from a controlled squat depth without turning the rep into a jump. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Squat / Knee-Dominant Bodyweight Strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_pause_bodyweight_squat_strength', '{"primary_joint_actions":["hip_flexion","knee_flexion","ankle_dorsiflexion","hip_extension","knee_extension"],"primary_tissues":["quadriceps","glutes","adductors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Pause Bodyweight Squat is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Clear a non-slip training space and choose a variation the athlete can control without pain.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Start each repetition from a still, organized position.","Move through the strength range with control, using only as much speed as the coaching intent allows.","Drive through the concentric portion with strong intent while keeping the same body line and joint path.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."]}'::jsonb),
  ('Wall Sit', 'wall-sit', 'Wall Sit is a isometric bodyweight strength hold. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'BEGINNER', 8, 3, NULL, 20, 90, 110, 'Isometric knee-dominant hold that builds quadriceps strength endurance and position tolerance with almost no skill barrier or impact. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Squat / Knee-Dominant Bodyweight Strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_wall_sit_strength', '{"primary_joint_actions":["knee_flexion_isometric","hip_flexion_isometric"],"primary_tissues":["quadriceps","glutes"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Wall Sit is a isometric bodyweight strength hold. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Set up near a stable wall with enough clear space to enter and exit safely.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Enter the target position under control instead of jumping or collapsing into it.","Create full-body tension in the target tissues while keeping breathing controlled.","Hold only as long as alignment, pain-free position, and calm bracing remain intact.","Exit the position with the same control used to enter it, then rest before the next set."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."]}'::jsonb),
  ('Bodyweight Split Squat', 'bodyweight-split-squat', 'Bodyweight Split Squat is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'INTERMEDIATE', 8, 3, 8, 40, 90, 130, 'Stationary single-leg-biased squat pattern that builds unilateral leg strength without momentum, impact, or forward lunge shear. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Unilateral Squat / Lunge Bodyweight Strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_bodyweight_split_squat_strength', '{"primary_joint_actions":["hip_flexion","knee_flexion","ankle_dorsiflexion","hip_extension","knee_extension"],"primary_tissues":["quadriceps","glutes","adductors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Bodyweight Split Squat is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Clear a non-slip training space and choose a variation the athlete can control without pain.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Start each repetition from a still, organized position.","Move through the strength range with control, using only as much speed as the coaching intent allows.","Drive through the concentric portion with strong intent while keeping the same body line and joint path.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."]}'::jsonb),
  ('Bodyweight Reverse Lunge', 'bodyweight-reverse-lunge', 'Bodyweight Reverse Lunge is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'INTERMEDIATE', 8, 3, 8, 40, 90, 130, 'Backward-stepping lunge that trains single-leg force production, hip control, and repeatable front-leg alignment with less forward knee shear than many forward lunges. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Unilateral Squat / Lunge Bodyweight Strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_bodyweight_reverse_lunge_strength', '{"primary_joint_actions":["hip_flexion","knee_flexion","hip_extension","knee_extension"],"primary_tissues":["quadriceps","glutes","adductors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Bodyweight Reverse Lunge is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Clear a non-slip training space and choose a variation the athlete can control without pain.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Start each repetition from a still, organized position.","Move through the strength range with control, using only as much speed as the coaching intent allows.","Drive through the concentric portion with strong intent while keeping the same body line and joint path.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."]}'::jsonb),
  ('Bodyweight Step-Up', 'bodyweight-step-up', 'Bodyweight Step-Up is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'INTERMEDIATE', 8, 3, 8, 40, 90, 130, 'Box-supported single-leg strength exercise that develops front-leg drive and controlled lowering without needing jumps. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Unilateral Squat / Lunge Bodyweight Strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_bodyweight_step_up_strength', '{"primary_joint_actions":["hip_flexion","knee_flexion","hip_extension","knee_extension"],"primary_tissues":["quadriceps","glutes","calves"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Bodyweight Step-Up is a lower-body bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Use a stable box or bench height that allows clean range without bouncing or joint collapse.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Start each repetition from a still, organized position.","Move through the strength range with control, using only as much speed as the coaching intent allows.","Drive through the concentric portion with strong intent while keeping the same body line and joint path.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."]}'::jsonb),
