  ('RKC Plank', 'rkc-plank', 'RKC Plank is a isometric bodyweight strength hold. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'BEGINNER', 8, 3, NULL, 20, 90, 110, 'High-tension plank that teaches whole-body bracing, glute tension, lat engagement, and anti-extension strength in short sets. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: tissue / capacity / isometric / eccentric / accessory. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Trunk / Body-Line Bodyweight Strength', 'capacity', 'tissue_capacity_isometric_eccentric_accessory', 'bodyweight_rkc_plank_strength', '{"primary_joint_actions":["spinal_anti_extension","shoulder_extension_isometric","hip_extension_isometric"],"primary_tissues":["abdominals","glutes","lats","serratus_anterior"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"RKC Plank is a isometric bodyweight strength hold. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Use a mat if the position places pressure on knees, wrists, back, or elbows.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Choose the lever length that allows strong bracing without breath panic or compensation."],"execution_steps":["Enter the target position under control instead of jumping or collapsing into it.","Create full-body tension in the target tissues while keeping breathing controlled.","Hold only as long as alignment, pain-free position, and calm bracing remain intact.","Exit the position with the same control used to enter it, then rest before the next set."],"coach_cues":["Brace hard.","Breathe behind the brace.","Hold the line.","Stop before shape breaks."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Holding breath until the athlete panics or shakes out of position.","Changing lever length without keeping the target trunk shape."]}'::jsonb),
  ('L-Sit', 'l-sit', 'L-Sit is a isometric bodyweight strength hold. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'ADVANCED', 8, 3, NULL, 12, 120, 135, 'Seated or support-position compression hold that builds hip-flexor strength, triceps support, shoulder depression, and trunk stiffness. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: tissue / capacity / isometric / eccentric / accessory. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Trunk / Compression Bodyweight Strength', 'capacity', 'tissue_capacity_isometric_eccentric_accessory', 'bodyweight_l_sit_strength', '{"primary_joint_actions":["hip_flexion_isometric","knee_extension_isometric","scapular_depression_isometric","trunk_brace"],"primary_tissues":["hip_flexors","quadriceps","triceps","lower_traps","abdominals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"L-Sit is a isometric bodyweight strength hold. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Check that the bar, rings, straps, or support are secure and appropriate for the athlete''s size and strength.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Choose the lever length that allows strong bracing without breath panic or compensation."],"execution_steps":["Enter the target position under control instead of jumping or collapsing into it.","Create full-body tension in the target tissues while keeping breathing controlled.","Hold only as long as alignment, pain-free position, and calm bracing remain intact.","Exit the position with the same control used to enter it, then rest before the next set."],"coach_cues":["Brace hard.","Breathe behind the brace.","Hold the line.","Stop before shape breaks."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Holding breath until the athlete panics or shakes out of position.","Changing lever length without keeping the target trunk shape."]}'::jsonb),
  ('Hanging Knee Raise', 'hanging-knee-raise', 'Hanging Knee Raise is a hanging bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'INTERMEDIATE', 8, 3, 6, 35, 120, 155, 'Hanging trunk-flexion and hip-flexion exercise that builds grip, shoulder control, and anterior-core strength without swinging. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: tissue / capacity / isometric / eccentric / accessory. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Trunk / Hanging Bodyweight Strength', 'capacity', 'tissue_capacity_isometric_eccentric_accessory', 'bodyweight_hanging_knee_raise_strength', '{"primary_joint_actions":["hip_flexion","spinal_flexion_control","scapular_depression_isometric","grip_isometric"],"primary_tissues":["abdominals","hip_flexors","forearms","lats"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"inverted_or_hanging","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hanging Knee Raise is a hanging bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Check that the bar, rings, straps, or support are secure and appropriate for the athlete''s size and strength.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Set the grip, shoulder position, and hollow or lightly braced body line before pulling or holding."],"execution_steps":["Start each repetition from a still, organized position.","Move through the strength range with control, using only as much speed as the coaching intent allows.","Keep the main lever organized and avoid swinging, twisting, or chasing momentum.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the hang first.","Shoulders stay active.","Hollow the ribs down.","No kicking or swinging."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Kipping, kicking, or swinging to finish the rep.","Losing active shoulder position at the bottom.","Chin reaches while ribs flare or neck strains."]}'::jsonb),
  ('Hanging Straight-Leg Raise', 'hanging-straight-leg-raise', 'Hanging Straight-Leg Raise is a hanging bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.', 'ADVANCED', 8, 3, 4, 30, 120, 150, 'Advanced hanging anterior-core and compression exercise that increases lever length for stronger hip-flexor, abdominal, grip, and shoulder-control demand. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: tissue / capacity / isometric / eccentric / accessory. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.', 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.', 'Trunk / Hanging Bodyweight Strength', 'capacity', 'tissue_capacity_isometric_eccentric_accessory', 'bodyweight_hanging_straight_leg_raise_strength', '{"primary_joint_actions":["hip_flexion","spinal_flexion_control","knee_extension_isometric","grip_isometric"],"primary_tissues":["abdominals","hip_flexors","quadriceps","forearms","lats"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_controlled","balance_demand":"inverted_or_hanging","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Hanging Straight-Leg Raise is a hanging bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Check that the bar, rings, straps, or support are secure and appropriate for the athlete''s size and strength.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Set the grip, shoulder position, and hollow or lightly braced body line before pulling or holding."],"execution_steps":["Start each repetition from a still, organized position.","Move through the strength range with control, using only as much speed as the coaching intent allows.","Keep the main lever organized and avoid swinging, twisting, or chasing momentum.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the hang first.","Shoulders stay active.","Hollow the ribs down.","No kicking or swinging."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Kipping, kicking, or swinging to finish the rep.","Losing active shoulder position at the bottom.","Chin reaches while ribs flare or neck strains."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
