  ('hanging-straight-leg-raise', 'Use only with medical clearance when appropriate and symptom-free bracing. Avoid breath-holding, excessive intra-abdominal pressure, coning, pelvic heaviness, leaking, or pain.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

